"use server";

import prisma from "@/lib/prisma";
import crypto from "crypto";
import { ActivityAction, NotificationType, Prisma } from "@prisma/client";

interface LogActivityParams {
  ticketId: string;
  performedById: string;
  action: ActivityAction;
  description: string;
  previousValue?: string;
  newValue?: string;
  metadata?: Record<string, unknown>;
}

// A helper function to hash the previous log entry with the new one
function generateLogHash(previousHash: string | null, newData: any) {
  const dataString = JSON.stringify({ prev: previousHash, data: newData });
  return crypto.createHash("sha256").update(dataString).digest("hex");
}

/**
 * Log an activity to a ticket's audit trail
 */
export async function logActivity(params: LogActivityParams) {
  // 1. Get the most recent log for this ticket
  const lastLog = await prisma.activityLog.findFirst({
    where: { ticketId: params.ticketId },
    orderBy: { createdAt: "desc" },
  });

  const previousHash = lastLog?.hash || null;
  const newHash = generateLogHash(previousHash, {
    ticketId: params.ticketId,
    userId: params.performedById,
    action: params.action,
    description: params.description,
    previousValue: params.previousValue,
    newValue: params.newValue,
    metadata: params.metadata,
  });

  // 2. Create the new tamper-proof log
  return prisma.activityLog.create({
    data: {
      ticketId: params.ticketId,
      performedById: params.performedById,
      action: params.action,
      description: params.description,
      previousValue: params.previousValue || null,
      newValue: params.newValue || null,
      metadata: params.metadata ? (params.metadata as Prisma.InputJsonValue) : undefined,
      hash: newHash, // The new chained hash
    },
  });
}

interface CreateNotificationParams {
  userId: string;
  ticketId: string;
  type: NotificationType;
  title: string;
  message: string;
  link?: string;
}

/**
 * Create an in-app notification for a user
 */
export async function createNotification(params: CreateNotificationParams) {
  return prisma.notification.create({
    data: {
      userId: params.userId,
      ticketId: params.ticketId,
      type: params.type,
      title: params.title,
      message: params.message,
      link: params.link || `/tickets/${params.ticketId}`,
    },
  });
}

/**
 * Notify relevant users based on ticket action
 */
export async function notifyOnTicketAction(
  ticketId: string,
  action: "created" | "assigned" | "status_changed" | "commented",
  actorId: string,
  extra?: { assigneeId?: string; newStatus?: string; ticketTitle?: string }
) {
  const ticket = await prisma.ticket.findUnique({
    where: { id: ticketId },
    include: {
      createdBy: true,
      assignedTo: true,
      property: { include: { manager: true } },
    },
  });

  if (!ticket) return;

  const title = extra?.ticketTitle || ticket.title;
  const notifications: CreateNotificationParams[] = [];

  switch (action) {
    case "created":
      // Notify property manager
      if (ticket.property.managerId && ticket.property.managerId !== actorId) {
        notifications.push({
          userId: ticket.property.managerId,
          ticketId,
          type: NotificationType.TICKET_CREATED,
          title: "New Maintenance Request",
          message: `New request: "${title}" submitted for ${ticket.property.name}`,
        });
      }
      break;

    case "assigned":
      // Notify the assigned technician
      if (extra?.assigneeId && extra.assigneeId !== actorId) {
        notifications.push({
          userId: extra.assigneeId,
          ticketId,
          type: NotificationType.TICKET_ASSIGNED,
          title: "New Assignment",
          message: `You've been assigned to: "${title}"`,
        });
      }
      break;

    case "status_changed":
      // Notify tenant of status changes
      if (ticket.createdById !== actorId) {
        notifications.push({
          userId: ticket.createdById,
          ticketId,
          type: NotificationType.STATUS_UPDATE,
          title: "Request Updated",
          message: `Your request "${title}" is now ${extra?.newStatus?.replace("_", " ").toLowerCase()}`,
        });
      }
      // Notify manager if staff completed
      if (
        extra?.newStatus === "COMPLETED" &&
        ticket.property.managerId &&
        ticket.property.managerId !== actorId
      ) {
        notifications.push({
          userId: ticket.property.managerId,
          ticketId,
          type: NotificationType.STATUS_UPDATE,
          title: "Work Completed",
          message: `"${title}" has been marked as completed and needs verification`,
        });
      }
      break;

    case "commented":
      // Notify all parties except the commenter
      const usersToNotify = new Set<string>();
      if (ticket.createdById !== actorId) usersToNotify.add(ticket.createdById);
      if (ticket.assignedToId && ticket.assignedToId !== actorId) usersToNotify.add(ticket.assignedToId);
      if (ticket.property.managerId && ticket.property.managerId !== actorId) usersToNotify.add(ticket.property.managerId);

      usersToNotify.forEach((userId) => {
        notifications.push({
          userId,
          ticketId,
          type: NotificationType.COMMENT_ADDED,
          title: "New Comment",
          message: `New comment on "${title}"`,
        });
      });
      break;
  }

  // Batch create all notifications
  if (notifications.length > 0) {
    await prisma.notification.createMany({
      data: notifications.map((n) => ({
        userId: n.userId,
        ticketId: n.ticketId,
        type: n.type,
        title: n.title,
        message: n.message,
        link: `/tickets/${ticketId}`,
      })),
    });
  }
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input, Label, Separator } from "@/components/ui/form-elements";
import { loginAction, quickLoginAction } from "@/actions/auth";
import { Building2, Home, Wrench, Shield, Loader2 } from "lucide-react";

export default function LoginPage() {
    const [error, setError] = useState("");
    const [loading, setLoading] = useState<string | null>(null);

    async function handleLogin(formData: FormData) {
        setLoading("login");
        setError("");
        const result = await loginAction(formData);
        if (result?.error) { setError(result.error); setLoading(null); }
    }

    async function handleQuickLogin(role: "tenant" | "manager" | "staff") {
        setLoading(role);
        setError("");
        const result = await quickLoginAction(role);
        if (result?.error) { setError(result.error); setLoading(null); }
    }

    return (
        <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-teal-50 via-white to-slate-50">
            <div className="w-full max-w-md space-y-6">
                {/* Brand */}
                <div className="text-center space-y-2">
                    <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-primary text-primary-foreground shadow-lg shadow-primary/25">
                        <Building2 className="w-7 h-7" />
                    </div>
                    <h1 className="text-2xl font-bold tracking-tight">PropMaint</h1>
                    <p className="text-muted-foreground text-sm">Property Maintenance Management System</p>
                </div>

                {/* Quick Login - THE KEY FEATURE FOR JUDGES */}
                <Card className="border-2 border-primary/20 shadow-lg">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base">Quick Demo Access</CardTitle>
                        <CardDescription>Try each role instantly — no signup needed</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        <Button onClick={() => handleQuickLogin("tenant")} disabled={!!loading}
                            className="w-full h-12 justify-start gap-3 bg-amber-50 text-amber-900 border border-amber-200 hover:bg-amber-100 shadow-none"
                            variant="outline">
                            {loading === "tenant" ? <Loader2 className="w-5 h-5 animate-spin" /> : <Home className="w-5 h-5 text-amber-600" />}
                            <div className="text-left">
                                <div className="font-semibold text-sm">Login as Tenant</div>
                                <div className="text-xs text-amber-600/80">Sarah Johnson — Submit &amp; track requests</div>
                            </div>
                        </Button>
                        <Button onClick={() => handleQuickLogin("manager")} disabled={!!loading}
                            className="w-full h-12 justify-start gap-3 bg-teal-50 text-teal-900 border border-teal-200 hover:bg-teal-100 shadow-none"
                            variant="outline">
                            {loading === "manager" ? <Loader2 className="w-5 h-5 animate-spin" /> : <Shield className="w-5 h-5 text-teal-600" />}
                            <div className="text-left">
                                <div className="font-semibold text-sm">Login as Manager</div>
                                <div className="text-xs text-teal-600/80">Michael Chen — Assign &amp; oversee all work</div>
                            </div>
                        </Button>
                        <Button onClick={() => handleQuickLogin("staff")} disabled={!!loading}
                            className="w-full h-12 justify-start gap-3 bg-blue-50 text-blue-900 border border-blue-200 hover:bg-blue-100 shadow-none"
                            variant="outline">
                            {loading === "staff" ? <Loader2 className="w-5 h-5 animate-spin" /> : <Wrench className="w-5 h-5 text-blue-600" />}
                            <div className="text-left">
                                <div className="font-semibold text-sm">Login as Technician</div>
                                <div className="text-xs text-blue-600/80">James Rodriguez — Resolve assigned tasks</div>
                            </div>
                        </Button>
                    </CardContent>
                </Card>

                {/* Regular Login */}
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base">Sign In</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <form action={handleLogin} className="space-y-4">
                            {error && (
                                <div className="p-3 rounded-lg bg-destructive/10 text-destructive text-sm">{error}</div>
                            )}
                            <div className="space-y-2">
                                <Label htmlFor="email">Email</Label>
                                <Input id="email" name="email" type="email" placeholder="you@example.com" required />
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="password">Password</Label>
                                <Input id="password" name="password" type="password" placeholder="••••••••" required />
                            </div>
                            <Button type="submit" className="w-full" disabled={!!loading}>
                                {loading === "login" ? <Loader2 className="w-4 h-4 animate-spin" /> : "Sign In"}
                            </Button>
                        </form>
                    </CardContent>
                </Card>

                <p className="text-center text-xs text-muted-foreground">
                    Built for the Qwego PropTech Challenge &middot; All data is demo/mock
                </p>
            </div>
        </div>
    );
}

import { auth } from "@/lib/auth";
import { redirect } from "next/navigation";
import prisma from "@/lib/prisma";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { BarChart3, Clock, CheckCircle2, AlertTriangle } from "lucide-react";

export default async function AnalyticsPage() {
    const session = await auth();
    if (session?.user?.role !== "MANAGER") redirect("/dashboard");

    const managerId = session.user.id;
    const where = { property: { managerId } };

    const [total, byStatus, byPriority, byCategory, avgResolution] = await Promise.all([
        prisma.ticket.count({ where }),
        prisma.ticket.groupBy({ by: ["status"], where, _count: true }),
        prisma.ticket.groupBy({ by: ["priority"], where, _count: true }),
        prisma.ticket.groupBy({ by: ["category"], where, _count: true }),
        prisma.ticket.aggregate({ where: { ...where, completedAt: { not: null } }, _avg: { actualCost: true } }),
    ]);

    const completedTickets = await prisma.ticket.findMany({
        where: { ...where, completedAt: { not: null }, startedAt: { not: null } },
        select: { startedAt: true, completedAt: true },
    });

    const avgResolutionHours = completedTickets.length > 0
        ? Math.round(completedTickets.reduce((sum, t) => {
            return sum + (new Date(t.completedAt!).getTime() - new Date(t.startedAt!).getTime()) / 3600000;
        }, 0) / completedTickets.length)
        : 0;

    const slaBroken = await prisma.ticket.count({ where: { ...where, slaBroken: true } });
    const slaCompliance = total > 0 ? Math.round(((total - slaBroken) / total) * 100) : 100;

    return (
        <div className="space-y-6 max-w-4xl">
            <div>
                <h1 className="text-xl font-bold tracking-tight">Analytics</h1>
                <p className="text-sm text-muted-foreground">Performance overview across all properties</p>
            </div>

            {/* KPI Cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                <KPICard icon={<BarChart3 className="w-4 h-4" />} label="Total Tickets" value={total.toString()} color="text-foreground" />
                <KPICard icon={<Clock className="w-4 h-4" />} label="Avg Resolution" value={`${avgResolutionHours}h`} color="text-blue-600" />
                <KPICard icon={<CheckCircle2 className="w-4 h-4" />} label="SLA Compliance" value={`${slaCompliance}%`}
                    color={slaCompliance >= 90 ? "text-emerald-600" : slaCompliance >= 70 ? "text-amber-600" : "text-red-600"} />
                <KPICard icon={<AlertTriangle className="w-4 h-4" />} label="SLA Breaches" value={slaBroken.toString()} color="text-red-600" />
            </div>

            {/* Status Breakdown */}
            <Card>
                <CardHeader className="pb-2"><CardTitle className="text-sm">Tickets by Status</CardTitle></CardHeader>
                <CardContent>
                    <div className="space-y-2">
                        {byStatus.map(s => (
                            <div key={s.status} className="flex items-center gap-3">
                                <span className="text-xs font-medium w-24">{s.status.replace("_", " ")}</span>
                                <div className="flex-1 bg-muted rounded-full h-3">
                                    <div className="h-3 rounded-full bg-primary/70 transition-all"
                                        style={{ width: `${total > 0 ? (s._count / total) * 100 : 0}%` }} />
                                </div>
                                <span className="text-xs font-semibold w-8 text-right">{s._count}</span>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            {/* Priority + Category */}
            <div className="grid md:grid-cols-2 gap-4">
                <Card>
                    <CardHeader className="pb-2"><CardTitle className="text-sm">By Priority</CardTitle></CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {byPriority.map(p => (
                                <div key={p.priority} className="flex items-center justify-between text-sm">
                                    <span>{p.priority}</span>
                                    <span className="font-semibold">{p._count}</span>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2"><CardTitle className="text-sm">By Category</CardTitle></CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {byCategory.map(c => (
                                <div key={c.category} className="flex items-center justify-between text-sm">
                                    <span>{c.category.replace("_", " ")}</span>
                                    <span className="font-semibold">{c._count}</span>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

function KPICard({ icon, label, value, color }: { icon: React.ReactNode; label: string; value: string; color: string }) {
    return (
        <Card>
            <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-2">
                    <span className={color}>{icon}</span>
                    <span className="text-xs font-medium text-muted-foreground">{label}</span>
                </div>
                <p className={`text-2xl font-bold ${color}`}>{value}</p>
            </CardContent>
        </Card>
    );
}

import { getNotifications, markAllNotificationsRead } from "@/actions/tickets";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { formatRelativeTime } from "@/lib/utils";
import { Bell, BellOff, CheckCheck } from "lucide-react";
import Link from "next/link";

export default async function NotificationsPage() {
    const notifications = await getNotifications();
    const unread = notifications.filter(n => !n.read);
    const read = notifications.filter(n => n.read);

    return (
        <div className="space-y-4 max-w-2xl">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-xl font-bold tracking-tight">Notifications</h1>
                    <p className="text-sm text-muted-foreground">{unread.length} unread</p>
                </div>
                {unread.length > 0 && (
                    <form action={markAllNotificationsRead}>
                        <Button variant="outline" size="sm" type="submit" className="gap-1 text-xs">
                            <CheckCheck className="w-3.5 h-3.5" /> Mark all read
                        </Button>
                    </form>
                )}
            </div>

            {notifications.length === 0 ? (
                <Card>
                    <CardContent className="py-16 text-center">
                        <BellOff className="w-10 h-10 mx-auto text-muted-foreground/40 mb-3" />
                        <p className="text-muted-foreground">No notifications</p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-2">
                    {unread.length > 0 && (
                        <>
                            <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider px-1">New</p>
                            {unread.map(n => (
                                <Link key={n.id} href={n.link || `/tickets/${n.ticketId}`}>
                                    <Card className="hover:shadow-md transition-all border-primary/20 bg-primary/[0.02]">
                                        <CardContent className="p-4 flex items-start gap-3">
                                            <div className="w-2 h-2 rounded-full bg-primary mt-2 shrink-0" />
                                            <div className="flex-1 min-w-0">
                                                <p className="text-sm font-semibold">{n.title}</p>
                                                <p className="text-xs text-muted-foreground mt-0.5">{n.message}</p>
                                                <p className="text-[10px] text-muted-foreground mt-1">{formatRelativeTime(n.createdAt)}</p>
                                            </div>
                                        </CardContent>
                                    </Card>
                                </Link>
                            ))}
                        </>
                    )}

                    {read.length > 0 && (
                        <>
                            <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider px-1 mt-4">Earlier</p>
                            {read.map(n => (
                                <Link key={n.id} href={n.link || `/tickets/${n.ticketId}`}>
                                    <Card className="hover:shadow-sm transition-all opacity-70 hover:opacity-100">
                                        <CardContent className="p-4 flex items-start gap-3">
                                            <div className="w-2 h-2 rounded-full bg-muted mt-2 shrink-0" />
                                            <div className="flex-1 min-w-0">
                                                <p className="text-sm font-medium">{n.title}</p>
                                                <p className="text-xs text-muted-foreground mt-0.5">{n.message}</p>
                                                <p className="text-[10px] text-muted-foreground mt-1">{formatRelativeTime(n.createdAt)}</p>
                                            </div>
                                        </CardContent>
                                    </Card>
                                </Link>
                            ))}
                        </>
                    )}
                </div>
            )}
        </div>
    );
}

import { auth } from "@/lib/auth";
import { getStaffMembers } from "@/actions/tickets";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Phone, Mail, Wrench } from "lucide-react";

function UserAvatar({ src, name }: { src?: string | null; name: string }) {
    if (!src) {
        return (
            <div className="w-10 h-10 rounded-full bg-primary/10 text-primary flex items-center justify-center text-sm font-semibold">
                {name?.split(" ").map(n => n[0]).join("")}
            </div>
        );
    }
    return <img src={src} alt={name} className="w-10 h-10 rounded-full object-cover" />;
}

export default async function TeamPage() {
    const session = await auth();
    if (session?.user?.role !== "MANAGER") {
        return (
            <div className="text-muted-foreground text-sm">
                Contact your property manager for team information.
            </div>
        );
    }

    const staff = await getStaffMembers();

    return (
        <div className="space-y-4 max-w-4xl">
            <div>
                <h1 className="text-xl font-bold tracking-tight">Team</h1>
                <p className="text-sm text-muted-foreground">{staff.length} technician{staff.length !== 1 ? "s" : ""}</p>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {staff.map((member) => (
                    <Card key={member.id} className="hover:shadow-md transition-shadow">
                        <CardContent className="p-4">
                            <div className="flex items-center gap-3 mb-3">
                                <UserAvatar src={member.avatarUrl} name={member.name} />
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-semibold truncate">{member.name}</p>
                                    <p className="text-xs text-muted-foreground">{member._count.assignedTickets} active ticket{member._count.assignedTickets !== 1 ? "s" : ""}</p>
                                </div>
                            </div>

                            {member.specialties.length > 0 && (
                                <div className="flex flex-wrap gap-1 mb-3">
                                    {member.specialties.map((s) => (
                                        <Badge key={s} variant="outline" className="text-[10px] gap-1">
                                            <Wrench className="w-2.5 h-2.5" />
                                            {s.replace("_", " ")}
                                        </Badge>
                                    ))}
                                </div>
                            )}

                            <div className="space-y-1">
                                {member.email && (
                                    <p className="text-xs text-muted-foreground flex items-center gap-1.5">
                                        <Mail className="w-3 h-3" /> {member.email}
                                    </p>
                                )}
                                {member.phone && (
                                    <p className="text-xs text-muted-foreground flex items-center gap-1.5">
                                        <Phone className="w-3 h-3" /> {member.phone}
                                    </p>
                                )}
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>
        </div>
    );
}

import { getTicketById, getStaffMembers } from "@/actions/tickets";
import { auth } from "@/lib/auth";
import { notFound } from "next/navigation";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/form-elements";
import { STATUS_CONFIG, PRIORITY_CONFIG, CATEGORY_CONFIG, getNextStatuses } from "@/lib/permissions";
import { formatDate, formatRelativeTime } from "@/lib/utils";
import { TicketActions } from "@/components/tickets/ticket-actions";
import { ActivityTimeline } from "@/components/tickets/activity-timeline";
import { CommentSection } from "@/components/tickets/comment-section";
import { FileUpload } from "@/components/tickets/file-upload";
import {
    MapPin, Clock, User, Wrench, CalendarDays, DollarSign,
    Shield, AlertTriangle, Phone, Mail,
} from "lucide-react";

export default async function TicketDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const session = await auth();
    const ticket = await getTicketById(id);
    if (!ticket || !session) return notFound();

    const statusCfg = STATUS_CONFIG[ticket.status];
    const priorityCfg = PRIORITY_CONFIG[ticket.priority];
    const catCfg = CATEGORY_CONFIG[ticket.category];
    const nextStatuses = getNextStatuses(ticket.status, session.user.role);
    const staffMembers = session.user.role === "MANAGER" ? await getStaffMembers() : [];
    const canComment = true;
    const canInternalNote = session.user.role === "MANAGER" || session.user.role === "STAFF";

    // SLA calculation
    const slaInfo = ticket.slaDeadline ? (() => {
        const now = new Date();
        const deadline = new Date(ticket.slaDeadline!);
        const remaining = deadline.getTime() - now.getTime();
        const hours = Math.floor(remaining / 3600000);
        const isBreached = remaining < 0;
        const isWarning = !isBreached && hours < (PRIORITY_CONFIG[ticket.priority].slaHours * 0.25);
        return { isBreached, isWarning, hours, deadline };
    })() : null;

    return (
        <div className="space-y-4 max-w-4xl">
            {/* Back + title */}
            <div>
                <a href="/tickets" className="text-sm text-muted-foreground hover:text-foreground transition-colors">← Back to tickets</a>
                <div className="flex items-start gap-3 mt-2">
                    <span className="text-2xl">{catCfg.emoji}</span>
                    <div className="flex-1">
                        <h1 className="text-xl font-bold tracking-tight">{ticket.title}</h1>
                        <div className="flex items-center gap-2 mt-1.5 flex-wrap">
                            <Badge variant={statusCfg.variant as any}>{statusCfg.label}</Badge>
                            <Badge variant={priorityCfg.variant as any}>{priorityCfg.label}</Badge>
                            <span className="text-xs text-muted-foreground">#{ticket.id.slice(-6)}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* SLA Warning Banner */}
            {slaInfo && (slaInfo.isBreached || slaInfo.isWarning) && !["COMPLETED", "VERIFIED", "CLOSED"].includes(ticket.status) && (
                <Card className={slaInfo.isBreached ? "border-red-300 bg-red-50" : "border-amber-300 bg-amber-50"}>
                    <CardContent className="p-3 flex items-center gap-3">
                        <AlertTriangle className={`w-5 h-5 ${slaInfo.isBreached ? "text-red-600" : "text-amber-600"}`} />
                        <div>
                            <p className={`text-sm font-semibold ${slaInfo.isBreached ? "text-red-900" : "text-amber-900"}`}>
                                {slaInfo.isBreached ? "SLA Breached" : "SLA Warning"}
                            </p>
                            <p className={`text-xs ${slaInfo.isBreached ? "text-red-700" : "text-amber-700"}`}>
                                {slaInfo.isBreached
                                    ? `Deadline was ${formatRelativeTime(slaInfo.deadline)}`
                                    : `${slaInfo.hours}h remaining — deadline ${formatDate(slaInfo.deadline)}`}
                            </p>
                        </div>
                    </CardContent>
                </Card>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                {/* Main content */}
                <div className="lg:col-span-2 space-y-4">
                    {/* Description */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm">Description</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm whitespace-pre-wrap">{ticket.description}</p>
                            {ticket.resolution && (
                                <div className="mt-4 p-3 rounded-lg bg-emerald-50 border border-emerald-200">
                                    <p className="text-xs font-semibold text-emerald-800 mb-1">Resolution</p>
                                    <p className="text-sm text-emerald-900">{ticket.resolution}</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* Attachments / File Upload */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm">Attachments</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <FileUpload
                                ticketId={ticket.id}
                                existingAttachments={ticket.attachments}
                            />
                        </CardContent>
                    </Card>

                    {/* Actions */}
                    <TicketActions
                        ticketId={ticket.id}
                        currentStatus={ticket.status}
                        nextStatuses={nextStatuses}
                        staffMembers={staffMembers}
                        currentAssigneeId={ticket.assignedToId}
                        userRole={session.user.role}
                    />

                    {/* Comments */}
                    <CommentSection
                        ticketId={ticket.id}
                        comments={ticket.comments}
                        canComment={canComment}
                        canInternalNote={canInternalNote}
                        currentUserId={session.user.id}
                    />

                    {/* Activity Timeline */}
                    <ActivityTimeline activities={ticket.activities} />
                </div>

                {/* Sidebar */}
                <div className="space-y-4">
                    {/* Details card */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm">Details</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-3">
                            <DetailRow icon={<MapPin className="w-4 h-4" />} label="Location"
                                value={`${ticket.property.name} · ${ticket.unit.building.name} · Unit ${ticket.unit.number}`} />
                            <DetailRow icon={<CalendarDays className="w-4 h-4" />} label="Created" value={formatDate(ticket.createdAt)} />
                            {ticket.slaDeadline && (
                                <DetailRow icon={<Clock className="w-4 h-4" />} label="SLA Deadline" value={formatDate(ticket.slaDeadline)} />
                            )}
                            <DetailRow icon={<Shield className="w-4 h-4" />} label="Entry Permission"
                                value={ticket.permissionToEnter ? "Granted" : "Not granted"} />
                            {ticket.preferredTimes && (
                                <DetailRow icon={<Clock className="w-4 h-4" />} label="Preferred Times" value={ticket.preferredTimes} />
                            )}
                            {(ticket.estimatedCost || ticket.actualCost) && (
                                <DetailRow icon={<DollarSign className="w-4 h-4" />} label="Cost"
                                    value={ticket.actualCost ? `$${ticket.actualCost} (actual)` : `$${ticket.estimatedCost} (est.)`} />
                            )}
                        </CardContent>
                    </Card>

                    {/* People */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm">People</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-3">
                            <PersonRow label="Submitted by" name={ticket.createdBy.name} role={ticket.createdBy.role}
                                email={ticket.createdBy.email} phone={ticket.createdBy.phone} />
                            {ticket.assignedTo ? (
                                <PersonRow label="Assigned to" name={ticket.assignedTo.name} role={ticket.assignedTo.role}
                                    email={ticket.assignedTo.email} phone={ticket.assignedTo.phone} />
                            ) : (
                                <div>
                                    <p className="text-xs text-muted-foreground">Assigned to</p>
                                    <p className="text-sm italic text-muted-foreground">Unassigned</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

function DetailRow({ icon, label, value }: { icon: React.ReactNode; label: string; value: string }) {
    return (
        <div className="flex items-start gap-2">
            <span className="text-muted-foreground mt-0.5 shrink-0">{icon}</span>
            <div>
                <p className="text-xs text-muted-foreground">{label}</p>
                <p className="text-sm">{value}</p>
            </div>
        </div>
    );
}

function PersonRow({ label, name, role, email, phone }: { label: string; name: string; role: string; email?: string | null; phone?: string | null }) {
    return (
        <div>
            <p className="text-xs text-muted-foreground">{label}</p>
            <p className="text-sm font-medium">{name}</p>
            <p className="text-xs text-muted-foreground capitalize">{role.toLowerCase()}</p>
            {email && <p className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5"><Mail className="w-3 h-3" />{email}</p>}
            {phone && <p className="text-xs text-muted-foreground flex items-center gap-1"><Phone className="w-3 h-3" />{phone}</p>}
        </div>
    );
}

import { auth } from "@/lib/auth";
