import { pipeline, env } from '@xenova/transformers';

// Tell Transformers.js to only download the model from the Hugging Face hub (browser mode)
env.allowLocalModels = false;

class PipelineSingleton {
    static task: any = 'zero-shot-classification';
    // We use a tiny, quantized model specifically optimized for mobile/browsers
    static model = 'Xenova/mobilebert-uncased-mnli';
    static instance: any = null;

    static async getInstance(progress_callback: any) {
        if (this.instance === null) {
            this.instance = pipeline(this.task, this.model, { progress_callback });
        }
        return this.instance;
    }
}

self.addEventListener('message', async (event: any) => {
    const { text, labels } = event.data;

    // Load the pipeline
    let classifier = await PipelineSingleton.getInstance((x: any) => {
        // We can send loading progress back to the UI
        self.postMessage(x);
    });

    // Run the zero-shot classification
    let output = await classifier(text, labels);

    self.postMessage({
        status: 'complete',
        output: output,
    });
});

// A simplified queue using localStorage for immediate demo purposes.
// In a full production app, you'd use IndexedDB (e.g., via the 'idb' library) for more robust storage.

const QUEUE_KEY = 'prop_maint_offline_queue';

export const SyncManager = {
    queueMutation: (mutation: any) => {
        if (typeof window === 'undefined') return;
        const currentQueue = JSON.parse(localStorage.getItem(QUEUE_KEY) || '[]');
        currentQueue.push(mutation);
        localStorage.setItem(QUEUE_KEY, JSON.stringify(currentQueue));
    },

    getQueue: () => {
        if (typeof window === 'undefined') return [];
        return JSON.parse(localStorage.getItem(QUEUE_KEY) || '[]');
    },

    clearQueue: () => {
        if (typeof window === 'undefined') return;
        localStorage.removeItem(QUEUE_KEY);
    }
};

"use client";

import { useState, useEffect, useRef } from 'react';

export function useAITriage() {
    const [result, setResult] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState(0);
    const worker = useRef<Worker | null>(null);

    useEffect(() => {
        if (!worker.current) {
            // Initialize the worker
            worker.current = new Worker(new URL('./ai-worker.ts', import.meta.url), {
                type: 'module'
            });
        }

        const onMessageReceived = (e: MessageEvent) => {
            switch (e.data.status) {
                case 'init':
                case 'progress':
                    setProgress(e.data.progress || 0);
                    break;
                case 'complete':
                    setResult(e.data.output);
                    setIsProcessing(false);
                    break;
            }
        };

        worker.current.addEventListener('message', onMessageReceived);
        return () => worker.current?.removeEventListener('message', onMessageReceived);
    }, []);

    const analyzeIssue = (text: string) => {
        if (!worker.current || !text) return;
        setIsProcessing(true);
        setResult(null);

        // The categories we want the AI to choose from
        const labels = ["plumbing", "electrical", "appliance", "structural", "security", "emergency leak", "fire"];

        worker.current.postMessage({ text, labels });
    };

    return { analyzeIssue, result, isProcessing, progress };
}

